// Command audit finds every production struct field that retains a handle to
// the cluster-state storage layer (lib/backend.Backend), the cache over it
// (lib/cache.Cache), or a narrowed interface view that either satisfies.
package main

import (
	"encoding/json"
	"fmt"
	"go/ast"
	"go/token"
	"go/types"
	"os"
	"sort"
	"strings"

	"golang.org/x/tools/go/packages"
)

type finding struct {
	Pos       string   `json:"pos"`
	Pkg       string   `json:"pkg"`
	Struct    string   `json:"struct"`
	Field     string   `json:"field"`
	TypeStr   string   `json:"type"`
	Kind      string   `json:"kind"`
	IfaceDecl string   `json:"iface_decl,omitempty"`
	Methods   []string `json:"methods,omitempty"`
	Local     bool     `json:"iface_local"`
}

func main() {
	cfg := &packages.Config{
		Mode: packages.NeedName | packages.NeedFiles | packages.NeedSyntax |
			packages.NeedTypes | packages.NeedTypesInfo | packages.NeedImports |
			packages.NeedDeps | packages.NeedCompiledGoFiles,
		Tests: false,
		Dir:   "..",
	}
	pkgs, err := packages.Load(cfg, "./...")
	if err != nil {
		fmt.Fprintln(os.Stderr, "load:", err)
		os.Exit(1)
	}

	const backendPath = "github.com/gravitational/teleport/lib/backend"
	const cachePath = "github.com/gravitational/teleport/lib/cache"

	var backendIface *types.Interface
	var cacheNamed *types.Named
	var backendNamed *types.Named

	packages.Visit(pkgs, nil, func(p *packages.Package) {
		if p.Types == nil {
			return
		}
		switch p.PkgPath {
		case backendPath:
			if o := p.Types.Scope().Lookup("Backend"); o != nil {
				if n, ok := o.Type().(*types.Named); ok {
					backendNamed = n
					if i, ok := n.Underlying().(*types.Interface); ok {
						backendIface = i
					}
				}
			}
		case cachePath:
			if o := p.Types.Scope().Lookup("Cache"); o != nil {
				if n, ok := o.Type().(*types.Named); ok {
					cacheNamed = n
				}
			}
		}
	})
	if backendIface == nil || cacheNamed == nil {
		fmt.Fprintf(os.Stderr, "could not resolve targets: backend=%v cache=%v\n", backendIface != nil, cacheNamed != nil)
		os.Exit(1)
	}
	ptrCache := types.NewPointer(cacheNamed)

	// isBackendImpl reports whether t is a concrete implementation of backend.Backend.
	isBackendImpl := func(t types.Type) bool {
		if types.Identical(t, backendNamed) {
			return false
		}
		if _, ok := t.Underlying().(*types.Interface); ok {
			return false
		}
		return types.Implements(t, backendIface) || types.Implements(types.NewPointer(t), backendIface)
	}

	var out []finding
	seen := map[string]bool{}

	packages.Visit(pkgs, nil, func(p *packages.Package) {
		if p.Types == nil || len(p.Syntax) == 0 {
			return
		}
		// Skip vendored / example / e2e trees.
		if strings.Contains(p.PkgPath, "/vendor/") {
			return
		}
		fset := p.Fset
		for _, f := range p.Syntax {
			fname := fset.Position(f.Pos()).Filename
			if strings.HasSuffix(fname, "_test.go") || strings.Contains(fname, "/testdata/") {
				continue
			}
			ast.Inspect(f, func(n ast.Node) bool {
				ts, ok := n.(*ast.TypeSpec)
				if !ok {
					return true
				}
				st, ok := ts.Type.(*ast.StructType)
				if !ok {
					return true
				}
				structName := ts.Name.Name
				for _, fld := range st.Fields.List {
					ft := p.TypesInfo.TypeOf(fld.Type)
					if ft == nil {
						continue
					}
					kind, iface := classify(ft, backendNamed, backendIface, cacheNamed, ptrCache, isBackendImpl)
					if kind == "" {
						continue
					}
					names := []string{}
					for _, nm := range fld.Names {
						names = append(names, nm.Name)
					}
					fieldName := strings.Join(names, ", ")
					if fieldName == "" {
						fieldName = "<embedded>"
					}
					pos := fset.Position(fld.Pos())
					rel := relPath(pos.Filename)
					key := fmt.Sprintf("%s:%d:%s", rel, pos.Line, fieldName)
					if seen[key] {
						continue
					}
					seen[key] = true

					fd := finding{
						Pos:     fmt.Sprintf("%s:%d", rel, pos.Line),
						Pkg:     p.PkgPath,
						Struct:  structName,
						Field:   fieldName,
						TypeStr: types.TypeString(ft, relQualifier),
						Kind:    kind,
					}
					if iface != nil {
						if nm, ok := iface.(*types.Named); ok {
							fd.IfaceDecl = nm.Obj().Pkg().Path() + "." + nm.Obj().Name()
							fd.Local = nm.Obj().Pkg().Path() == p.PkgPath
							if u, ok := nm.Underlying().(*types.Interface); ok {
								for i := 0; i < u.NumMethods(); i++ {
									fd.Methods = append(fd.Methods, u.Method(i).Name())
								}
							}
						}
					}
					out = append(out, fd)
				}
				return true
			})
		}
	})

	sort.Slice(out, func(i, j int) bool { return out[i].Pos < out[j].Pos })
	enc := json.NewEncoder(os.Stdout)
	enc.SetIndent("", " ")
	enc.Encode(out)
	fmt.Fprintf(os.Stderr, "findings: %d\n", len(out))
}

// classify returns a retention kind for a field type, plus the interface type if narrowed.
func classify(ft types.Type, backendNamed *types.Named, backendIface *types.Interface,
	cacheNamed *types.Named, ptrCache types.Type, isBackendImpl func(types.Type) bool,
) (string, types.Type) {
	// unwrap one level of pointer/slice/map/array for the "holds" question
	base := ft
	switch t := ft.(type) {
	case *types.Pointer:
		if n, ok := t.Elem().(*types.Named); ok && n == cacheNamed {
			return "cache-direct", nil
		}
		base = t.Elem()
	case *types.Slice:
		base = t.Elem()
	case *types.Map:
		base = t.Elem()
	}

	if n, ok := base.(*types.Named); ok {
		if n == cacheNamed {
			return "cache-direct", nil
		}
		if n == backendNamed {
			return "backend-direct", nil
		}
	}

	named, isNamed := base.(*types.Named)
	if !isNamed {
		return "", nil
	}
	u, ok := named.Underlying().(*types.Interface)
	if !ok {
		// concrete type implementing backend.Backend (e.g. *lite.Backend, *memory.Memory)
		if isBackendImpl(base) {
			return "backend-impl", nil
		}
		return "", nil
	}
	if u.NumMethods() == 0 {
		return "", nil
	}
	cacheSat := types.Implements(ptrCache, u)
	backendSat := types.Implements(backendNamed, u)
	switch {
	case cacheSat && backendSat:
		return "narrowed-both", named
	case cacheSat:
		return "cache-narrowed", named
	case backendSat:
		return "backend-narrowed", named
	}
	return "", nil
}

func relQualifier(p *types.Package) string { return p.Name() }

func relPath(f string) string {
	const marker = "/teleport/"
	if i := strings.LastIndex(f, marker); i >= 0 {
		return f[i+len(marker):]
	}
	return f
}

var _ = token.NoPos

